%[text] # 例4.1（二次元余弦波）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example04_01"; % mfilename
%%
N = 128;
[Qx,Qy] = meshgrid(-0.5:1/N:0.5-1/N,-0.5:1/N:0.5-1/N);
%%
nus = {[0;2*pi],[4*pi;0],[4*pi;2*pi]};
labels = {"a","b","c"};
for idx=1:3 %[output:group:1ea6798d]
    nuv = nus{idx}(1);
    nuh = nus{idx}(2);
    b = @(qv,qh) cos(nuv.*qv+nuh.*qh);

    figure(idx) %[output:3ac1af27] %[output:341eacd9] %[output:646501a4]
    h = surf(Qx,Qy,b(Qy,Qx)); %[output:3ac1af27] %[output:341eacd9] %[output:646501a4]
    %axis off
    daspect([1 1 8])
    colormap("gray")
    h.EdgeColor = "none";
    shading interp
    xlabel("$q_\mathrm{h}$","Interpreter","latex")
    ylabel("$q_\mathrm{v}$","Interpreter","latex")
    ax = gca;
    ax.YDir = 'reverse';
    ax.Color = 'none';
    ax.FontSize = 20; %[output:0ae07c6a] %[output:132db82d] %[output:34be410c]
    fg = gcf;
    fg.Color = 'none'; %[output:3ac1af27] %[output:341eacd9] %[output:646501a4]
    set(fg,'Renderer','opengl');
    exportgraphics(fg,fullfile(resfolder,"fig04-02"+labels{idx}+".png"),'BackgroundColor','none','ContentType','image') %[output:5d091738] %[output:3ac1af27] %[output:62111580] %[output:341eacd9] %[output:1d2f521c] %[output:646501a4]
end %[output:group:1ea6798d]

